// Simulate GBP completeness check via Google My Business indicators
// In production, use Google My Business API or scrape GBP public data
const checks = [
  { factor: 'business_name', weight: 10, present: true },
  { factor: 'address', weight: 10, present: true },
  { factor: 'phone', weight: 10, present: true },
  { factor: 'website', weight: 10, present: true },
  { factor: 'hours', weight: 10, present: true },
  { factor: 'description', weight: 10, present: true },
  { factor: 'categories', weight: 10, present: true },
  { factor: 'photos_recent', weight: 15, present: false },
  { factor: 'posts_this_month', weight: 10, present: false },
  { factor: 'qa_responses', weight: 5, present: false }
];
const score = checks.reduce((sum, c) => sum + (c.present ? c.weight : 0), 0);
const missing = checks.filter(c => !c.present).map(c => c.factor);
return [{ json: { gbp_score: score, missing_factors: missing.join(','), checked_at: new Date().toISOString(), needs_alert: score < 80 } }];
